import { serve } from "https://deno.land/std@0.168.0/http/server.ts"

const DEFAULT_REPO = "GetyeTek/Notify"; 

serve(async (req) => {
  const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
  };

  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });

  try {
    const gitHubToken = Deno.env.get('GITHUB_PAT');
    if (!gitHubToken) throw new Error("Server Error: Missing GITHUB_PAT");

    let body = {};
    try { const text = await req.text(); if (text) body = JSON.parse(text); } catch (e) {}

    const { action, repo, run_id, job_id } = body;
    const targetRepo = repo || DEFAULT_REPO;

    console.log(`[${req.method}] Action: ${action}, Repo: ${targetRepo}`);

    const ghHeaders = {
      "Authorization": `Bearer ${gitHubToken}`,
      "Accept": "application/vnd.github.v3+json",
    };

    // 1. FETCH RUNS
    if (action === 'fetch_runs') {
      const url = `https://api.github.com/repos/${targetRepo}/actions/runs?per_page=10`;
      const res = await fetch(url, { headers: ghHeaders });
      if (!res.ok) throw new Error(`GitHub API Error ${res.status}`);
      const data = await res.json();

      const runs = (data.workflow_runs || []).map((r: any) => ({
        id: r.id,
        run_number: r.run_number,
        name: r.name,
        status: r.status,
        conclusion: r.conclusion || "unknown",
        commit_msg: r.head_commit?.message || "No commit message"
      }));

      return new Response(JSON.stringify({ success: true, runs }), { headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
    }

    // 2. FETCH ARTIFACT DOWNLOAD LINK
    if (action === 'fetch_artifact_link' && run_id) {
        // A. List artifacts for this run
        const listUrl = `https://api.github.com/repos/${targetRepo}/actions/runs/${run_id}/artifacts`;
        const listRes = await fetch(listUrl, { headers: ghHeaders });
        const listData = await listRes.json();

        if (!listData.artifacts || listData.artifacts.length === 0) {
            return new Response(JSON.stringify({ success: false, error: "No artifacts found" }), { headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
        }

        // B. Get the download URL for the first artifact (assuming it's the APK/Zip)
        const artifact = listData.artifacts[0];
        const downloadApiUrl = artifact.archive_download_url;

        // C. HIT the API with the Token. GitHub will respond with a 302 Redirect to Azure Blob Storage.
        // We capture that redirect URL. The Azure URL is signed and works WITHOUT headers.
        const redirectRes = await fetch(downloadApiUrl, { 
            headers: ghHeaders,
            redirect: "manual" // Stop fetch from following the redirect automatically
        });

        const finalUrl = redirectRes.headers.get("location");

        if (!finalUrl) {
            throw new Error("Could not retrieve signed storage URL from GitHub");
        }

        return new Response(JSON.stringify({ success: true, url: finalUrl }), { headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
    }

    // Keep these for backward compatibility if needed, or remove them
    if (action === 'fetch_jobs' && run_id) {
       return new Response(JSON.stringify({ success: true, jobs: [] }), { headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
    }

    return new Response(JSON.stringify({ success: false, error: "Invalid Action" }), { status: 400, headers: corsHeaders });

  } catch (error) {
    console.error(error);
    return new Response(JSON.stringify({ success: false, error: error.message }), { headers: { ...corsHeaders, 'Content-Type': 'application/json' }, status: 500 });
  }
});

