// 2. FETCH ARTIFACT DOWNLOAD LINK
if (action === 'fetch_artifact_link' && run_id) {
    // A. List artifacts for this run
    const listUrl = `https://api.github.com/repos/${targetRepo}/actions/runs/${run_id}/artifacts`;
    const listRes = await fetch(listUrl, { headers: ghHeaders });
    const listData = await listRes.json();

    if (!listData.artifacts || listData.artifacts.length === 0) {
        return new Response(JSON.stringify({ success: false, error: "No artifacts found" }), { headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
    }

    // B. Get the download URL for the first artifact (assuming it's the APK/Zip)
    const artifact = listData.artifacts[0];
    const downloadApiUrl = artifact.archive_download_url;

    // C. HIT the API with the Token. GitHub will respond with a 302 Redirect to Azure Blob Storage.
    // We capture that redirect URL. The Azure URL is signed and works WITHOUT headers.
    const redirectRes = await fetch(downloadApiUrl, { 
        headers: ghHeaders,
        redirect: "manual" // Stop fetch from following the redirect automatically
    });

    const finalUrl = redirectRes.headers.get("location");

    if (!finalUrl) {
        throw new Error("Could not retrieve signed storage URL from GitHub");
    }

    return new Response(JSON.stringify({ success: true, url: finalUrl }), { headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
}

