private fun startAutoDownload(url: String, runNumber: Int) {
    val request = DownloadManager.Request(Uri.parse(url))
        .setTitle("Auto-Updating Build #\$runNumber")
        .setDescription("Notify Realtime Automatic Update")
        .setNotificationVisibility(DownloadManager.Request.VISIBILITY_VISIBLE)
        .setDestinationInExternalPublicDir(Environment.DIRECTORY_DOWNLOADS, "notify-auto-\$runNumber.zip")

    val dm = getSystemService(Context.DOWNLOAD_SERVICE) as DownloadManager
    dm.enqueue(request)
}

private val onDownloadComplete = object : BroadcastReceiver() {
    override fun onReceive(context: Context, intent: Intent) {
        val id = intent.getLongExtra(DownloadManager.EXTRA_DOWNLOAD_ID, -1)
        if (id == -1L) return

        val dm = context.getSystemService(Context.DOWNLOAD_SERVICE) as DownloadManager
        val query = DownloadManager.Query().setFilterById(id)
        val cursor = dm.query(query)
        if (cursor.moveToFirst()) {
            val status = cursor.getInt(cursor.getColumnIndex(DownloadManager.COLUMN_STATUS))
            val fileUriString = cursor.getString(cursor.getColumnIndex(DownloadManager.COLUMN_LOCAL_URI))
            cursor.close()

            if (status == DownloadManager.STATUS_SUCCESSFUL && fileUriString != null) {
                processDownloadedZip(Uri.parse(fileUriString))
            }
        }
    }
}

private fun processDownloadedZip(zipUri: Uri) {
    val zipFile = File(zipUri.path ?: return)
    val outputDir = File(getExternalFilesDir(null), "extracted_update")
    if (!outputDir.exists()) outputDir.mkdirs()

    serviceScope.launch(Dispatchers.IO) {
        try {
            var apkFile: File? = null
            contentResolver.openInputStream(zipUri)?.use { input ->
                ZipInputStream(input).use { zis ->
                    var entry = zis.nextEntry
                    while (entry != null) {
                        if (entry.name.endsWith(".apk")) {
                            val destFile = File(outputDir, "update.apk")
                            FileOutputStream(destFile).use { fos -> zis.copyTo(fos) }
                            apkFile = destFile
                            break
                        }
                        zis.closeEntry()
                        entry = zis.nextEntry
                    }
                }
            }

            if (apkFile != null) {
                triggerInstallation(apkFile!!)
            }
        } catch (e: Exception) { e.printStackTrace() }
    }
}

private fun triggerInstallation(file: File) {
    val apkUri = FileProvider.getUriForFile(this, "com.getyetek.notify.fileprovider", file)
    val installIntent = Intent(Intent.ACTION_VIEW).apply {
        setDataAndType(apkUri, "application/vnd.android.package-archive")
        addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION)
        addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
    }
    startActivity(installIntent)
}

